class SecureURLSessionDelegate: NSObject, URLSessionDelegate {
    static let shared = SecureURLSessionDelegate()
    
    private override init() {
        super.init()
    }
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard let serverTrust = challenge.protectionSpace.serverTrust,
              challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        let host = challenge.protectionSpace.host
        
        if SecureHTTPClient.shared.isLocalNetworkAddress(host) {
            if SecureHTTPClient.shared.trustedLocalHosts.contains(host) {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
                return
            } else {
                completionHandler(.cancelAuthenticationChallenge, nil)
                return
            }
        }
        
        if let pinnedHashes = SecureHTTPClient.shared.certificatePins[host] {
            if validateCertificatePinning(serverTrust: serverTrust, pinnedHashes: pinnedHashes) {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
            } else {
                completionHandler(.cancelAuthenticationChallenge, nil)
            }
        } else {
            var secTrustResult = SecTrustResultType.invalid
            SecTrustEvaluate(serverTrust, &secTrustResult)
            
            if secTrustResult == .unspecified || secTrustResult == .proceed {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
            } else {
                completionHandler(.cancelAuthenticationChallenge, nil)
            }
        }
    }
    
    private func validateCertificatePinning(serverTrust: SecTrust, pinnedHashes: Set<String>) -> Bool {
        guard let certificates = SecTrustCopyCertificateChain(serverTrust) as? [SecCertificate] else {
            return false
        }
        
        for certificate in certificates {
            let certData = SecCertificateCopyData(certificate) as Data
            let hash = SHA256.hash(data: certData)
            let hashString = "sha256/" + Data(hash).base64EncodedString()
            
            if pinnedHashes.contains(hashString) {
                return true
            }
        }
        
        return false
    }
}

enum HTTPMethod: String {
    case get = "GET"
    case post = "POST"
