}

struct HTTPResponse {
    let statusCode: Int
    let headers: [String: String]
    let data: Data
    
    var isSuccess: Bool {
        return (200...299).contains(statusCode)
    }
    
    func decodeJSON<T: Decodable>() throws -> T {
        let decoder = JSONDecoder()
        return try decoder.decode(T.self, from: data)
    }
    
    var stringValue: String? {
        return String(data: data, encoding: .utf8)
    }
}

enum HTTPClientError: LocalizedError {
    case invalidURL
    case invalidScheme
    case invalidHost
    case invalidResponse
    case insecureConnectionNotAllowed(String)
    case untrustedLocalHost(String)
    case certificatePinningFailed
    
    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid URL provided"
        case .invalidScheme:
            return "Invalid URL scheme. Only HTTP and HTTPS are supported"
        case .invalidHost:
            return "Invalid host in URL"
        case .invalidResponse:
            return "Invalid response from server"
        case .insecureConnectionNotAllowed(let message):
            return message
        case .untrustedLocalHost(let message):
            return message
        case .certificatePinningFailed:
            return "Certificate pinning validation failed"
        }
    }
}

