    func discoverAndTrustDevice(ipAddress: String, completion: @escaping (Result<Void, Error>) -> Void) {
        guard SecureHTTPClient.shared.isLocalNetworkAddress(ipAddress) else {
            completion(.failure(HTTPClientError.invalidHost))
            return
        }
        
        httpClient.addTrustedLocalHost(ipAddress)
        
        guard let url = URL(string: "http://\(ipAddress)/api/info") else {
            completion(.failure(HTTPClientError.invalidURL))
            return
        }
        
        httpClient.get(url) { result in
            switch result {
            case .success(let response):
                if response.isSuccess {
                    completion(.success(()))
                } else {
                    completion(.failure(HTTPClientError.invalidResponse))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func sendCommandToDevice(ipAddress: String, command: [String: Any], completion: @escaping (Result<HTTPResponse, Error>) -> Void) {
        guard let url = URL(string: "http://\(ipAddress)/api/command") else {
            completion(.failure(HTTPClientError.invalidURL))
            return
        }
        
        guard let jsonData = try? JSONSerialization.data(withJSONObject: command) else {
            completion(.failure(HTTPClientError.invalidResponse))
            return
        }
        
        httpClient.post(url, body: jsonData, completion: completion)
    }
}

